#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define MAX 1000000

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int lcm(int a, int b) {
    return a * b / gcd(a, b);
}

int main() {
    int T, A, B, p, count, i;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &A, &B);
        count = 0;
        for (p = 1; p <= 1000000; p++) {
            if ((A - 1) % p == 0 && (B - 1) % p == 0) {
                count++;
            }
        }
        if (count == 0) {
            printf("-1\n");
        } else {
            printf("%d\n", count);
        }
    }
    return 0;
}

